arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed — throws in EF Core 9 Cosmos provider.
    // Cosmos DB indexing is managed via the container's indexing policy.

    // Preserve the old "Discriminator" property name (EF Core 9 defaults to "$type").
    // This keeps existing documents and raw SQL like
    //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
    // working without rewriting stored data.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve the old compound id format "Blog|1" (EF Core 9 defaults to key-only).
    // Without this, FindAsync and point-reads against existing documents fail.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

